import litellm

def smart_call(messages: list[dict], token_estimate: int) -> str:
    """Route to a larger context model when the prompt is too long."""
    if token_estimate > 120_000:
        model = 'anthropic/claude-opus-4-8'   # 200k context
    elif token_estimate > 60_000:
        model = 'openai/gpt-4o'               # 128k context
    else:
        model = 'openai/gpt-4o-mini'          # 128k context, cheaper

    response = litellm.completion(model=model, messages=messages)
    return response.choices[0].message.content

