from litellm import Router

# Priority routing: fast model first, slower/cheaper model as fallback,
# cheapest model for non-urgent batch traffic
router = Router(
    model_list=[
        {
            'model_name': 'priority-high',
            'litellm_params': {
                'model': 'openai/gpt-4o-mini',
                'api_key': 'sk-...',
                'rpm': 2000,
            },
        },
        {
            'model_name': 'priority-low',
            'litellm_params': {
                'model': 'meta-llama/llama-3.3-70b-instruct',
                'api_key': 'sk-or-...',
                'base_url': 'https://openrouter.ai/api/v1',
                'rpm': 1000,
            },
        },
    ],
    fallbacks=[{'priority-high': ['priority-low']}],
    routing_strategy='least-busy',
)

# Interactive path — use high priority alias
ui_response = router.completion(
    model='priority-high',
    messages=[{'role': 'user', 'content': 'Suggest a title for this article.'}],
)

# Background batch — use low-priority alias directly
batch_response = router.completion(
    model='priority-low',
    messages=[{'role': 'user', 'content': 'Summarise this document: ...'}],
)

import litellm

def stream_with_fallback(models: list[str], messages: list):
    """Stream from the first model that succeeds."""
    for model in models:
        try:
            stream = litellm.completion(
                model=model,
                messages=messages,
                stream=True,
            )
            for chunk in stream:
                delta = chunk.choices[0].delta.content
                if delta:
                    yield delta
            return   # stream completed successfully
        except litellm.exceptions.RateLimitError:
            if model == models[-1]:
                raise
            print(f'{model} rate limited, switching to {models[models.index(model)+1]}')

# Usage
for token in stream_with_fallback(
    models=['openai/gpt-4o-mini', 'anthropic/claude-haiku-4-5'],
    messages=[{'role': 'user', 'content': 'Explain TCP/IP in 3 sentences.'}],
):
    print(token, end='', flush=True)
